import React from 'react';
import Logo from './Logo.png'; 
import Menu from './Menu'; 

function App() {
  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', margin: 0, padding: 0 }}>
      
      {/* 1. THE LOGO SECTION (STAIN-KILLER VERSION) */}
      <header style={{ 
        width: '100vw', 
        height: '90vh',           // Logo takes up almost the whole screen
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        backgroundColor: '#000',
        overflow: 'hidden'
      }}>
        <img 
          src={Logo} 
          alt="Àmí by T" 
          style={{ 
            width: '100%', 
            height: '100%', 
            objectFit: 'contain',
            padding: '60px',
            
            /* THIS IS THE STAIN-KILLER FILTER */
            filter: 'contrast(160%) brightness(120%)', 
            mixBlendMode: 'screen'
          }} 
        />
      </header>

      {/* 2. THE MENU SECTION (SCROLL DOWN TO SEE) */}
      <main>
        <Menu />
      </main>

      {/* 3. FOOTER */}
      <footer style={{ textAlign: 'center', padding: '40px', color: '#222', fontSize: '0.7rem' }}>
        <p>© 2026 ÀMÍ BY T | LAGOS</p>
      </footer>

    </div>
  );
}

export default App;
